\n\nAnalyze the following 30-day ad performance data for {{$node['Split In Batches'].json['business_name']}} and identify the best hours and days to run ads. Data: {{JSON.stringify($input.all().map(i => i.json))}}. Return JSON with: best_hours (array of hours 0-23), best_days (array of day names), worst_hours, worst_days, recommendation. Return only valid JSON, no markdown."}]}

parameters.jsCode:
try {
  const items = $input.all();
  const results = [];
  for (const item of items) {
    const content = item.json.content && item.json.content[0] ? item.json.content[0].text : '';
    let parsed;
    try {
      parsed = JSON.parse(content);
    } catch(e) {
      const match = content.match(/\{[\s\S]*\}/);
      if (match) {
        parsed = JSON.parse(match[0]);
      } else {
        parsed = {
          best_hours: [9, 10, 11, 14, 15, 19, 20],
          best_days: ['Monday', 'Tuesday', 'Wednesday', 'Thursday'],
          worst_hours: [0, 1, 2, 3, 4, 5],
          worst_days: ['Saturday', 'Sunday'],
          recommendation: 'Run ads during business hours on weekdays for optimal performance.'
        };
      }
    }
    results.push({json: {
      business_id: $node['Split In Batches'].json.id,
      business_name: $node['Split In Batches'].json.business_name,
      email: $node['Split In Batches'].json.email || '',
      best_hours: parsed.best_hours || [],
      best_days: parsed.best_days || [],
      worst_hours: parsed.worst_hours || [],
      worst_days: parsed.worst_days || [],
      recommendation: parsed.recommendation || '',
      updated_at: new Date().toISOString()
    }});
  }
  return results;
} catch(e) {
  return [{json:{error: e.message, business_id: $node['Split In Batches'].json.id}}];
}
